SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY p.productNo ASC) AS recNum, p.productNo, p.productCategory, p.productName, p.productDescription, p.productPrice, p.productQty, p.productUpdated, p.productOptions, i.imageFileName FROM product p LEFT JOIN ( SELECT DISTINCT ON (articleNo) articleNo, imageFileName FROM image WHERE imageType = '상품' ORDER BY articleNo, imageNo ASC ) i ON i.articleNo = p.productNo WHERE p.productName IN ( SELECT productName FROM wishlist WHERE memberId = #{memberId} )
AND p.productCategory = #{category}
) t WHERE recNum BETWEEN ((#{pageNum}-1)*9 + 1) AND (#{pageNum}*9)

